arguments.file_text:
@page "/"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveServer

@using Microsoft.EntityFrameworkCore
@inject VetClinic.Data.ApplicationDbContext Db

<PageTitle>VetClinic - Dashboard</PageTitle>

<h1>Veterinary Clinic Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-3">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@petCount</p>
                <a href="/patients" class="btn btn-light btn-sm">Manage</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
                <a href="/appointments" class="btn btn-light btn-sm">View Schedule</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning mb-3">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-6">@pendingInvoices</p>
                <a href="/billing" class="btn btn-light btn-sm">View Billing</a>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info mb-3">
            <div class="card-body">
                <h5 class="card-title">Owners</h5>
                <p class="card-text display-6">@ownerCount</p>
                <a href="/patients" class="btn btn-light btn-sm">Manage</a>
            </div>
        </div>
    </div>
</div>

<h3 class="mt-4">Upcoming Appointments</h3>
@if (upcomingAppointments.Any())
{
    <table class="table table-striped">
        <thead>
            <tr><th>Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Vet</th></tr>
        </thead>
        <tbody>
            @foreach (var appt in upcomingAppointments)
            {
                <tr>
                    <td>@appt.StartTime.ToString("g")</td>
                    <td>@appt.Pet.Name</td>
                    <td>@appt.Pet.Owner.FullName</td>
                    <td>@appt.Reason</td>
                    <td>@appt.Veterinarian</td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <p class="text-muted">No upcoming appointments.</p>
}

@code {
    private int petCount;
    private int ownerCount;
    private int todayAppointments;
    private int pendingInvoices;
    private List<VetClinic.Data.Models.Appointment> upcomingAppointments = new();

    protected override async Task OnInitializedAsync()
    {
        petCount = await Db.Pets.CountAsync();
        ownerCount = await Db.Owners.CountAsync();
        var today = DateTime.Today;
        todayAppointments = await Db.Appointments
            .Where(a => a.StartTime.Date == today && a.Status == VetClinic.Data.Models.AppointmentStatus.Scheduled)
            .CountAsync();
        pendingInvoices = await Db.Invoices
            .Where(i => i.Status == VetClinic.Data.Models.InvoiceStatus.Pending)
            .CountAsync();
        upcomingAppointments = await Db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= DateTime.Now && a.Status == VetClinic.Data.Models.AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(10)
            .ToListAsync();
    }
}

@page "/patients"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveServer

@using Microsoft.EntityFrameworkCore
@using VetClinic.Data.Models
@inject VetClinic.Data.ApplicationDbContext Db

<PageTitle>Patients</PageTitle>

<h1>Patient Records</h1>

<div class="row mb-3">
    <div class="col">
        <input class="form-control" placeholder="Search pets or owners..." @bind="searchTerm" @bind:event="oninput" @bind:after="Search" />
    </div>
    <div class="col-auto">
        <button class="btn btn-primary" @onclick="ShowAddOwner">+ New Owner</button>
        <button class="btn btn-success ms-2" @onclick="ShowAddPet">+ New Pet</button>
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</div>
        <div class="card-body">
            <EditForm Model="editingOwner" OnValidSubmit="SaveOwner">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label>First Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.FirstName" />
                        <ValidationMessage For="() => editingOwner.FirstName" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label>Last Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.LastName" />
                        <ValidationMessage For="() => editingOwner.LastName" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Phone</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Phone" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Email</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Email" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Address</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Address" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary">Save</button>
                <button type="button" class="btn btn-secondary ms-2" @onclick="() => showOwnerForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingPet.Id == 0 ? "Register New Pet" : "Edit Pet")</div>
        <div class="card-body">
            <EditForm Model="editingPet" OnValidSubmit="SavePet">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-2 mb-2">
                        <label>Name</label>
                        <InputText class="form-control" @bind-Value="editingPet.Name" />
                        <ValidationMessage For="() => editingPet.Name" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Species</label>
                        <InputText class="form-control" @bind-Value="editingPet.Species" />
                        <ValidationMessage For="() => editingPet.Species" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Breed</label>
                        <InputText class="form-control" @bind-Value="editingPet.Breed" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="editingPet.DateOfBirth" />
                    </div>
                    <div class="col-md-1 mb-2">
                        <label>Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="editingPet.WeightKg" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label>Owner</label>
                        <InputSelect class="form-control" @bind-Value="editingPet.OwnerId">
                            <option value="0">-- Select Owner --</option>
                            @foreach (var owner in owners)
                            {
                                <option value="@owner.Id">@owner.FullName</option>
                            }
                        </InputSelect>
                    </div>
                </div>
                <div class="mb-2">
                    <label>Medical Notes</label>
                    <InputTextArea class="form-control" @bind-Value="editingPet.MedicalNotes" rows="2" />
                </div>
                <button type="submit" class="btn btn-primary">Save</button>
                <button type="button" class="btn btn-secondary ms-2" @onclick="() => showPetForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<table class="table table-hover">
    <thead>
        <tr><th>Pet</th><th>Species</th><th>Breed</th><th>Owner</th><th>Actions</th></tr>
    </thead>
    <tbody>
        @foreach (var pet in pets)
        {
            <tr>
                <td>@pet.Name</td>
                <td>@pet.Species</td>
                <td>@pet.Breed</td>
                <td>@pet.Owner.FullName</td>
                <td>
                    <a href="/patients/@pet.Id" class="btn btn-sm btn-outline-primary">View</a>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => EditPet(pet)">Edit</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@code {
    private List<Pet> pets = new();
    private List<Owner> owners = new();
    private string searchTerm = string.Empty;
    private bool showOwnerForm;
    private bool showPetForm;
    private Owner editingOwner = new();
    private Pet editingPet = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    private async Task Search()
    {
        var query = Db.Pets.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.ToLower();
            query = query.Where(p =>
                p.Name.ToLower().Contains(term) ||
                p.Species.ToLower().Contains(term) ||
                p.Owner.FirstName.ToLower().Contains(term) ||
                p.Owner.LastName.ToLower().Contains(term));
        }
        pets = await query.OrderBy(p => p.Name).ToListAsync();
    }

    private void ShowAddOwner()
    {
        editingOwner = new Owner();
        showOwnerForm = true;
        showPetForm = false;
    }

    private void ShowAddPet()
    {
        editingPet = new Pet();
        showPetForm = true;
        showOwnerForm = false;
    }

    private void EditPet(Pet pet)
    {
        editingPet = pet;
        showPetForm = true;
        showOwnerForm = false;
    }

    private async Task SaveOwner()
    {
        if (editingOwner.Id == 0)
            Db.Owners.Add(editingOwner);
        else
            Db.Owners.Update(editingOwner);
        await Db.SaveChangesAsync();
        showOwnerForm = false;
        await LoadData();
    }

    private async Task SavePet()
    {
        if (editingPet.OwnerId == 0) return;
        if (editingPet.Id == 0)
            Db.Pets.Add(editingPet);
        else
            Db.Pets.Update(editingPet);
        await Db.SaveChangesAsync();
        showPetForm = false;
        await LoadData();
    }
}

@page "/patients/{PetId:int}"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveServer

@using Microsoft.EntityFrameworkCore
@using VetClinic.Data.Models
@inject VetClinic.Data.ApplicationDbContext Db
@inject NavigationManager Nav

<PageTitle>Patient - @pet?.Name</PageTitle>

@if (pet == null)
{
    <p>Loading...</p>
}
else
{
    <h1>@pet.Name <small class="text-muted">(@pet.Species@(pet.Breed != null ? $" - {pet.Breed}" : ""))</small></h1>
    <p><strong>Owner:</strong> @pet.Owner.FullName | <strong>DOB:</strong> @(pet.DateOfBirth?.ToShortDateString() ?? "Unknown") | <strong>Weight:</strong> @(pet.WeightKg?.ToString("0.0") ?? "N/A") kg</p>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <span>Medical Notes</span>
            <button class="btn btn-sm btn-outline-primary" @onclick="() => editingMedicalNotes = true">Edit</button>
        </div>
        <div class="card-body">
            @if (editingMedicalNotes)
            {
                <textarea class="form-control mb-2" @bind="pet.MedicalNotes" rows="3"></textarea>
                <button class="btn btn-primary btn-sm" @onclick="SaveMedicalNotes">Save</button>
                <button class="btn btn-secondary btn-sm" @onclick="() => editingMedicalNotes = false">Cancel</button>
            }
            else
            {
                <p>@(string.IsNullOrEmpty(pet.MedicalNotes) ? "No medical notes." : pet.MedicalNotes)</p>
            }
        </div>
