@page "/appointments"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveServer

@using Microsoft.EntityFrameworkCore
@using VetClinic.Data.Models
@inject VetClinic.Data.ApplicationDbContext Db

<PageTitle>Appointments</PageTitle>

<h1>Appointment Schedule</h1>

<div class="row mb-3">
    <div class="col-md-3">
        <label>View Date</label>
        <input type="date" class="form-control" @bind="selectedDate" @bind:after="LoadAppointments" />
    </div>
    <div class="col-md-3 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowNewAppointment">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingAppointment.Id == 0 ? "New Appointment" : "Edit Appointment")</div>
        <div class="card-body">
            <EditForm Model="editingAppointment" OnValidSubmit="SaveAppointment">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label>Pet</label>
                        <InputSelect class="form-control" @bind-Value="editingAppointment.PetId">
                            <option value="0">-- Select Pet --</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Start Time</label>
                        <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="editingAppointment.StartTime" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>End Time</label>
                        <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="editingAppointment.EndTime" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Veterinarian</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Veterinarian" />
                    </div>
