@code {
    [Parameter] public int PetId { get; set; }

    private Pet? pet;
    private List<TreatmentNote> treatmentNotes = new();
    private bool editingMedicalNotes;
    private bool showTreatmentForm;
    private TreatmentNote editingNote = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadPet();
    }

    private async Task LoadPet()
    {
        pet = await Db.Pets.Include(p => p.Owner).FirstOrDefaultAsync(p => p.Id == PetId);
        treatmentNotes = await Db.TreatmentNotes
            .Where(t => t.PetId == PetId)
            .OrderByDescending(t => t.Date)
            .ToListAsync();
    }

    private async Task SaveMedicalNotes()
    {
        if (pet == null) return;
        Db.Pets.Update(pet);
        await Db.SaveChangesAsync();
        editingMedicalNotes = false;
    }

    private void ShowAddTreatment()
    {
        editingNote = new TreatmentNote { PetId = PetId, Date = DateTime.Now };
        showTreatmentForm = true;
    }

    private async Task SaveTreatment()
    {
        editingNote.PetId = PetId;
        if (editingNote.Id == 0)
            Db.TreatmentNotes.Add(editingNote);
        else
            Db.TreatmentNotes.Update(editingNote);
        await Db.SaveChangesAsync();
        showTreatmentForm = false;
        await LoadPet();
    }
}

@page "/appointments"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveServer

@using Microsoft.EntityFrameworkCore
@using VetClinic.Data.Models
@inject VetClinic.Data.ApplicationDbContext Db

<PageTitle>Appointments</PageTitle>

<h1>Appointment Schedule</h1>

<div class="row mb-3">
    <div class="col-md-3">
        <label>View Date</label>
        <input type="date" class="form-control" @bind="selectedDate" @bind:after="LoadAppointments" />
    </div>
    <div class="col-md-3 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowNewAppointment">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingAppointment.Id == 0 ? "New Appointment" : "Edit Appointment")</div>
        <div class="card-body">
            <EditForm Model="editingAppointment" OnValidSubmit="SaveAppointment">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label>Pet</label>
                        <InputSelect class="form-control" @bind-Value="editingAppointment.PetId">
                            <option value="0">-- Select Pet --</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Start Time</label>
                        <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="editingAppointment.StartTime" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>End Time</label>
                        <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="editingAppointment.EndTime" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Veterinarian</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Veterinarian" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label>Reason</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Reason" />
                        <ValidationMessage For="() => editingAppointment.Reason" />
                    </div>
                </div>
                <div class="mb-2">
                    <label>Notes</label>
                    <InputTextArea class="form-control" @bind-Value="editingAppointment.Notes" rows="2" />
                </div>
                @if (conflictMessage != null)
                {
                    <div class="alert alert-warning">@conflictMessage</div>
                }
                <button type="submit" class="btn btn-primary">Save</button>
                <button type="button" class="btn btn-secondary ms-2" @onclick="() => showForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<h4>Availability for @selectedDate.ToString("D")</h4>
<div class="row mb-3">
    @foreach (var slot in timeSlots)
    {
        var isBooked = bookedSlots.Contains(slot);
        <div class="col-auto mb-1">
            <span class="badge @(isBooked ? "bg-danger" : "bg-success") p-2">
                @slot.ToString("HH:mm") @(isBooked ? "Booked" : "Available")
            </span>
        </div>
    }
</div>

<h4>Appointments</h4>
<table class="table table-striped">
    <thead>
        <tr><th>Time</th><th>Pet</th><th>Owner</th><th>Vet</th><th>Reason</th><th>Status</th><th>Actions</th></tr>
    </thead>
    <tbody>
        @foreach (var appt in appointments)
        {
            <tr class="@(appt.Status == AppointmentStatus.Cancelled ? "table-secondary" : "")">
                <td>@appt.StartTime.ToString("HH:mm") - @appt.EndTime.ToString("HH:mm")</td>
                <td>@appt.Pet.Name</td>
                <td>@appt.Pet.Owner.FullName</td>
                <td>@appt.Veterinarian</td>
                <td>@appt.Reason</td>
                <td><span class="badge @StatusBadge(appt.Status)">@appt.Status</span></td>
                <td>
                    @if (appt.Status == AppointmentStatus.Scheduled)
                    {
                        <button class="btn btn-sm btn-outline-primary" @onclick="() => Reschedule(appt)">Reschedule</button>
                        <button class="btn btn-sm btn-outline-warning" @onclick="() => Complete(appt)">Complete</button>
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => Cancel(appt)">Cancel</button>
                    }
                </td>
            </tr>
        }
    </tbody>
</table>

@code {
    private DateTime selectedDate = DateTime.Today;
    private List<Appointment> appointments = new();
    private List<Pet> pets = new();
    private bool showForm;
    private Appointment editingAppointment = new();
    private string? conflictMessage;

    private List<DateTime> timeSlots = new();
    private HashSet<DateTime> bookedSlots = new();

    protected override async Task OnInitializedAsync()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        GenerateTimeSlots();
        await LoadAppointments();
    }

    private void GenerateTimeSlots()
    {
        timeSlots.Clear();
        for (int hour = 8; hour < 18; hour++)
        {
            timeSlots.Add(selectedDate.AddHours(hour));
            timeSlots.Add(selectedDate.AddHours(hour).AddMinutes(30));
        }
    }

    private async Task LoadAppointments()
    {
        GenerateTimeSlots();
        appointments = await Db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime.Date == selectedDate.Date)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

        bookedSlots = appointments
            .Where(a => a.Status == AppointmentStatus.Scheduled)
            .SelectMany(a => timeSlots.Where(t => t >= a.StartTime && t < a.EndTime))
            .ToHashSet();
    }

    private void ShowNewAppointment()
    {
        editingAppointment = new Appointment
        {
            StartTime = selectedDate.AddHours(9),
            EndTime = selectedDate.AddHours(9).AddMinutes(30)
        };
        conflictMessage = null;
        showForm = true;
    }

    private void Reschedule(Appointment appt)
    {
        editingAppointment = appt;
        conflictMessage = null;
        showForm = true;
    }

    private async Task SaveAppointment()
    {
        if (editingAppointment.PetId == 0) return;

        // Check for conflicts
        var hasConflict = await Db.Appointments
            .Where(a => a.Id != editingAppointment.Id
                && a.Status == AppointmentStatus.Scheduled
                && a.StartTime < editingAppointment.EndTime
                && a.EndTime > editingAppointment.StartTime
                && a.Veterinarian == editingAppointment.Veterinarian)
            .AnyAsync();

        if (hasConflict)
        {
            conflictMessage = "Time conflict: this vet already has an appointment during this slot.";
            return;
        }

        if (editingAppointment.Id == 0)
            Db.Appointments.Add(editingAppointment);
        else
            Db.Appointments.Update(editingAppointment);
        await Db.SaveChangesAsync();
        showForm = false;
        await LoadAppointments();
    }

    private async Task Cancel(Appointment appt)
    {
        appt.Status = AppointmentStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadAppointments();
    }

    private async Task Complete(Appointment appt)
    {
        appt.Status = AppointmentStatus.Completed;
        await Db.SaveChangesAsync();
        await LoadAppointments();
    }

    private string StatusBadge(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-light"
    };
}

