                            <tr>
                                <td>@p.PaidDate.ToShortDateString()</td>
                                <td>$@p.Amount.ToString("N2")</td>
                                <td>@p.Method</td>
                                <td>@p.Reference</td>
                            </tr>
                        }
                    </tbody>
                </table>
            }
            else
            {
                <p class="text-muted">No payments recorded.</p>
            }
            <button class="btn btn-secondary btn-sm" @onclick="() => showPaymentHistory = false">Close</button>
        </div>
    </div>
}

@code {
    private List<Invoice> invoices = new();
    private List<Pet> pets = new();
    private List<Payment> paymentHistory = new();
    private string statusFilter = string.Empty;
    private bool showInvoiceForm;
    private bool showPaymentForm;
    private bool showPaymentHistory;
    private Invoice editingInvoice = new();
    private Invoice? selectedInvoice;
    private Payment editingPayment = new();

    protected override async Task OnInitializedAsync()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        var query = Db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Payments)
            .AsQueryable();

        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<InvoiceStatus>(statusFilter, out var s))
            query = query.Where(i => i.Status == s);

        invoices = await query.OrderByDescending(i => i.IssuedDate).ToListAsync();
    }

    private void ShowNewInvoice()
    {
        editingInvoice = new Invoice { IssuedDate = DateTime.Now, DueDate = DateTime.Now.AddDays(30) };
        showInvoiceForm = true;
    }

    private async Task SaveInvoice()
    {
        if (editingInvoice.PetId == 0) return;
        if (editingInvoice.Id == 0)
            Db.Invoices.Add(editingInvoice);
        else
            Db.Invoices.Update(editingInvoice);
        await Db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadInvoices();
    }

    private void ShowPayment(Invoice inv)
    {
        selectedInvoice = inv;
        editingPayment = new Payment
        {
            InvoiceId = inv.Id,
            PaidDate = DateTime.Now,
            Amount = inv.Balance
        };
        showPaymentForm = true;
        showPaymentHistory = false;
    }

    private async Task SavePayment()
    {
        Db.Payments.Add(editingPayment);
        await Db.SaveChangesAsync();

        // Auto-mark as paid if balance is zero
        var invoice = await Db.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == editingPayment.InvoiceId);
        if (invoice.Balance <= 0)
            invoice.Status = InvoiceStatus.Paid;
        await Db.SaveChangesAsync();

        showPaymentForm = false;
        await LoadInvoices();
    }

    private async Task CancelInvoice(Invoice inv)
    {
        inv.Status = InvoiceStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadInvoices();
    }

    private async Task ViewPayments(Invoice inv)
    {
        selectedInvoice = inv;
        paymentHistory = await Db.Payments.Where(p => p.InvoiceId == inv.Id).OrderByDescending(p => p.PaidDate).ToListAsync();
        showPaymentHistory = true;
        showPaymentForm = false;
    }

    private string InvoiceBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        InvoiceStatus.Cancelled => "bg-secondary",
        _ => "bg-light"
    };
}

