{"file_text": "@page "/billing"
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]
@rendermode InteractiveServer

@using Microsoft.EntityFrameworkCore
@using VetClinic.Data.Models
@inject VetClinic.Data.ApplicationDbContext Db

<PageTitle>Billing</PageTitle>

<h1>Billing &amp; Invoices</h1>

<div class="row mb-3">
    <div class="col-md-3">
        <select class="form-control" @bind="statusFilter" @bind:after="LoadInvoices">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<InvoiceStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-auto">
        <button class="btn btn-primary" @onclick="ShowNewInvoice">+ New Invoice</button>
    </div>
</div>

@if (showInvoiceForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingInvoice.Id == 0 ? "Generate Invoice" : "Edit Invoice")</div>
        <div class="card-body">
            <EditForm Model="editingInvoice" OnValidSubmit="SaveInvoice">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label>Pet</label>
                        <InputSelect class="form-control" @bind-Value="editingInvoice.PetId">
                            <option value="0">-- Select Pet --</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Amount</label>
                        <InputNumber class="form-control" @bind-Value="editingInvoice.Amount" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Issued Date</label>
                        <InputDate class="form-control" @bind-Value="editingInvoice.IssuedDate" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Due Date</label>
                        <InputDate class="form-control" @bind-Value="editingInvoice.DueDate" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label>Description</label>
                        <InputText class="form-control" @bind-Value="editingInvoice.Description" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary">Save</button>
                <button type="button" class="btn btn-secondary ms-2" @onclick="() => showInvoiceForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<table class="table table-striped">
    <thead>
        <tr><th>#</th><th>Pet</th><th>Owner</th><th>Description</th><th>Amount</th><th>Paid</th><th>Balance</th><th>Status</th><th>Actions</th></tr>
    </thead>
    <tbody>
        @foreach (var inv in invoices)
        {
            <tr>
                <td>@inv.Id</td>
                <td>@inv.Pet.Name</td>
                <td>@inv.Pet.Owner.FullName</td>
                <td>@inv.Description</td>
                <td>$@inv.Amount.ToString("N2")</td>
                <td>$@inv.TotalPaid.ToString("N2")</td>
                <td>$@inv.Balance.ToString("N2")</td>
                <td><span class="badge @InvoiceBadge(inv.Status)">@inv.Status</span></td>
                <td>
                    @if (inv.Status == InvoiceStatus.Pending || inv.Status == InvoiceStatus.Overdue)
                    {
                        <button class="btn btn-sm btn-outline-success" @onclick="() => ShowPayment(inv)">Pay</button>
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelInvoice(inv)">Cancel</button>
                    }
                    <button class="btn btn-sm btn-outline-info" @onclick="() => ViewPayments(inv)">History</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@if (showPaymentForm)
{
    <div class="card mb-3">
        <div class="card-header">Process Payment - Invoice #@selectedInvoice!.Id (Balance: $@selectedInvoice!.Balance.ToString("N2"))</div>
        <div class="card-body">
            <EditForm Model="editingPayment" OnValidSubmit="SavePayment">
                <div class="row">
                    <div class="col-md-2 mb-2">
                        <label>Amount</label>
                        <InputNumber class="form-control" @bind-Value="editingPayment.Amount" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Date</label>
                        <InputDate class="form-control" @bind-Value="editingPayment.PaidDate" />
                    </div>
                    <div class="col-md-2 mb-2">
                        <label>Method</label>
                        <InputSelect class="form-control" @bind-Value="editingPayment.Method">
                            @foreach (var m in Enum.GetValues<PaymentMethod>())
                            {
                                <option value="@m">@m</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-3 mb-2">
                        <label>Reference</label>
                        <InputText class="form-control" @bind-Value="editingPayment.Reference" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success">Process Payment</button>
                <button type="button" class="btn btn-secondary ms-2" @onclick="() => showPaymentForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (showPaymentHistory && selectedInvoice != null)
{
    <div class="card mb-3">
        <div class="card-header">Payment History - Invoice #@selectedInvoice.Id</div>
        <div class="card-body">
            @if (paymentHistory.Any())
            {
                <table class="table table-sm">
                    <thead>
                        <tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th></tr>
                    </thead>
                    <tbody>
                        @foreach (var p in paymentHistory)
                        {
                            <tr>
                                <td>@p.PaidDate.ToShortDateString()</td>
                                <td>$@p.Amount.ToString("N2")</td>
                                <td>@p.Method</td>
                                <td>@p.Reference</td>
                            </tr>
                        }
                    </tbody>
                </table>
            }
            else
            {
                <p class="text-muted">No payments recorded.</p>
            }
            <button class="btn btn-secondary btn-sm" @onclick="() => showPaymentHistory = false">Close</button>
        </div>
    </div>
}

@code {
    private List<Invoice> invoices = new();
    private List<Pet> pets = new();
    private List<Payment> paymentHistory = new();
    private string statusFilter = string.Empty;
    private bool showInvoiceForm;
    private bool showPaymentForm;
    private bool showPaymentHistory;
    private Invoice editingInvoice = new();
    private Invoice? selectedInvoice;
    private Payment editingPayment = new();

    protected override async Task OnInitializedAsync()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadInvoices();
    }

    private async Task LoadInvoices()
    {
        var query = Db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Payments)
            .AsQueryable();

        if (!string.IsNullOrEmpty(statusFilter) && Enum.TryParse<InvoiceStatus>(statusFilter, out var s))
            query = query.Where(i => i.Status == s);

        invoices = await query.OrderByDescending(i => i.IssuedDate).ToListAsync();
    }

    private void ShowNewInvoice()
    {
        editingInvoice = new Invoice { IssuedDate = DateTime.Now, DueDate = DateTime.Now.AddDays(30) };
        showInvoiceForm = true;
    }

    private async Task SaveInvoice()
    {
        if (editingInvoice.PetId == 0) return;
        if (editingInvoice.Id == 0)
            Db.Invoices.Add(editingInvoice);
        else
            Db.Invoices.Update(editingInvoice);
        await Db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadInvoices();
    }

    private void ShowPayment(Invoice inv)
    {
        selectedInvoice = inv;
        editingPayment = new Payment
        {
            InvoiceId = inv.Id,
            PaidDate = DateTime.Now,
            Amount = inv.Balance
        };
        showPaymentForm = true;
        showPaymentHistory = false;
    }

    private async Task SavePayment()
    {
        Db.Payments.Add(editingPayment);
        await Db.SaveChangesAsync();

        // Auto-mark as paid if balance is zero
        var invoice = await Db.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == editingPayment.InvoiceId);
        if (invoice.Balance <= 0)
            invoice.Status = InvoiceStatus.Paid;
        await Db.SaveChangesAsync();

        showPaymentForm = false;
        await LoadInvoices();
    }

    private async Task CancelInvoice(Invoice inv)
    {
        inv.Status = InvoiceStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadInvoices();
    }

    private async Task ViewPayments(Invoice inv)
    {
        selectedInvoice = inv;
        paymentHistory = await Db.Payments.Where(p => p.InvoiceId == inv.Id).OrderByDescending(p => p.PaidDate).ToListAsync();
        showPaymentHistory = true;
        showPaymentForm = false;
    }

    private string InvoiceBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        InvoiceStatus.Cancelled => "bg-secondary",
        _ => "bg-light"
    };
}
