            }
        </div>
    </div>

    <h3>Treatment History</h3>
    <button class="btn btn-success btn-sm mb-2" @onclick="ShowAddTreatment">+ Add Treatment Note</button>

    @if (showTreatmentForm)
    {
        <div class="card mb-3">
            <div class="card-body">
                <EditForm Model="editingNote" OnValidSubmit="SaveTreatment">
                    <DataAnnotationsValidator />
                    <div class="row">
                        <div class="col-md-3 mb-2">
                            <label>Date</label>
                            <InputDate class="form-control" @bind-Value="editingNote.Date" />
                        </div>
                        <div class="col-md-4 mb-2">
                            <label>Title</label>
                            <InputText class="form-control" @bind-Value="editingNote.Title" />
                            <ValidationMessage For="() => editingNote.Title" />
                        </div>
                        <div class="col-md-3 mb-2">
                            <label>Veterinarian</label>
                            <InputText class="form-control" @bind-Value="editingNote.Veterinarian" />
                        </div>
                    </div>
                    <div class="mb-2">
                        <label>Description</label>
                        <InputTextArea class="form-control" @bind-Value="editingNote.Description" rows="3" />
                        <ValidationMessage For="() => editingNote.Description" />
                    </div>
                    <button type="submit" class="btn btn-primary btn-sm">Save</button>
                    <button type="button" class="btn btn-secondary btn-sm" @onclick="() => showTreatmentForm = false">Cancel</button>
                </EditForm>
            </div>
        </div>
    }

    @if (treatmentNotes.Any())
    {
        @foreach (var note in treatmentNotes)
        {
            <div class="card mb-2">
                <div class="card-body">
                    <h6>@note.Date.ToShortDateString() — @note.Title <small class="text-muted">(@note.Veterinarian)</small></h6>
                    <p class="mb-0">@note.Description</p>
                </div>
            </div>
        }
    }
    else
    {
        <p class="text-muted">No treatment notes yet.</p>
    }
}

@code {
    [Parameter] public int PetId { get; set; }

    private Pet? pet;
    private List<TreatmentNote> treatmentNotes = new();
    private bool editingMedicalNotes;
    private bool showTreatmentForm;
    private TreatmentNote editingNote = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadPet();
    }

    private async Task LoadPet()
    {
        pet = await Db.Pets.Include(p => p.Owner).FirstOrDefaultAsync(p => p.Id == PetId);
        treatmentNotes = await Db.TreatmentNotes
            .Where(t => t.PetId == PetId)
            .OrderByDescending(t => t.Date)
            .ToListAsync();
    }

    private async Task SaveMedicalNotes()
    {
        if (pet == null) return;
        Db.Pets.Update(pet);
        await Db.SaveChangesAsync();
        editingMedicalNotes = false;
    }

